@flask.Flask.route('/oauth2callback')
def oauth2callback():

    client = OpenIDClient()
    config = CLIENT['provider'][0] + '/.well-known/openid-configuration' \
                                     if 'provider' not in CLIENT else CLIENT['provider']

    try:
        state, params = client.decode_authorization_response(
            request_uri=flask.request.args.get('code'),  # request the authorization code for verification and get access token
            redirect_uri='http://127.0.0.1:5000/oauth2callback',   # verify using the callback URL
            provider=config
        )
    except ValueError:
        return 'Login Failed', flask.status_codes['HTTP_403_FORBIDDEN']

    try:  # request the user information and id token from the authorization server
        session = client().create_session(params, request)
    except Exception as e:   # handle the error of failed authentication (e.g., account suspended or expired due to OOB access or a typo in redirect URL)
        return 'Login Failed', flask.status_codes['HTTP_403_FORBIDDEN']

    try:  # verify id token for user's identity and authority
        claims = client().verify_access_token(
            request=request,  # the incoming HTTP request to be used in verification
            id_token=session['id_token'],
            issuer='https://accounts.google.com',   # check whether the ID token comes from Google or another provider
            audience=['your client id'],
        )
    except Exception as e:
        return 'Login Failed', flask.status_codes['HTTP_403_FORBIDDEN']

    flask.session.clear()  # clear user information to reset session
    flask.session = claims   # use the user's claims in Flask session instead of id token
    flask.session['id_token'] = session['id_token']    # pass the id token to the logout endpoint for Google authorization server

    return flask.redirect(flask.request.args.get('state')) if 'return' not in flask.session else \
        flask.redirect('/' + flask.session.pop('return'))


